1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
13	
14	const COMPONENT_TYPES = ["rune", "moonstone"];
15	const BLOCK_SIZE = 3;
16	const BLOCK_PREMIUM = 60;
17	
18	const componentPremium = (type: string, count: number): number =>
19	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * basePremiumForType(type);
20	
21	const itemPremium = (item: any): number => {
22	  const base = basePremiumForType(item.type);
23	  let premium = base;
24	  if (item.cursed) premium += base * 0.5;
25	  if (item.enchantment >= 5) premium += base * 0.3;
26	  return premium;
27	};
28	
29	const calculateQuotePremium = (items: any[]): number => {
30	  const componentCounts: Record<string, number> = {};
31	  let premium = 0;
32	  for (const item of items) {
33	    if (COMPONENT_TYPES.includes(item.type)) {
34	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
35	    } else {
36	      premium += itemPremium(item);
37	    }
38	  }
39	  for (const [type, count] of Object.entries(componentCounts)) {
40	    premium += componentPremium(type, count);
41	  }
42	  return premium + PROCESSING_FEE;
43	};
44	
45	export const processScenario = (scenario: any): any => ({
46	  results: scenario.steps.map((step: any) => ({
47	    premium: calculateQuotePremium(step.items),
48	  })),
49	});
